<template>
  <div class="bg-white" id="worker_all_rasxod_print">
    <div v-if="isPdfGenerating" class="pdf-progress">
      <div class="pdf-progress-dot"></div>
      <span>PDF yuklanayapti...</span>
    </div>
    <div class="p-4">
      <div class="bg-white p-4 mb-4 shadow" style="border-radius:5px; position:relative;">
        <form @submit.prevent="apply">
          <div class="d-flex justify-content-between border-bottom align-items-center">
            <div class="title w-75 row align-items-center no-print">
              <div class="col-3">
                <div style="position: relative; margin-top: 25px;">
                  <small class="bg-white" style="position: absolute; z-index:1; left:10px; top: -10px; color: #757575;">
                    {{$t('start_time')}}
                  </small>
                  <mdb-input type="date" size="sm" v-model="Start_time" outline/>
                </div>
              </div>
              <div class="col-3">
                <div style="position: relative; margin-top: 25px;">
                  <small class="bg-white" style="position: absolute; z-index:1; left:10px; top: -10px; color: #757575;">
                    {{$t('end_time')}}
                  </small>
                  <mdb-input type="date" size="sm" v-model="End_time" outline/>
                </div>
              </div>
              <div class="col-4">
                <div>
                  <erpSelect
                    :options="allWorker.rows"
                    @select="selectOptionWorker"
                    :selected="worker_name"
                    size="sm"
                    class="bg-white"
                    style="margin-top:8px;"
                    url="/TegirmonWorker/getPaginationSearchByFioOrPassportSerailNumberOrHomeOrMobilePhoneNumber?page=0&size=100&fio_or_serial_number="
                    label="Поиск сотрудник"
                  />
                </div>
              </div>
              <div class="col-2 p-0">
                <mdb-btn @click="apply" color="primary py-2 px-3" style="font-size:9px;">
                  <mdb-icon style="font-size:9.5px;" icon="check" class="m-0 p-0 mr-1" />
                  {{$t('apply')}}
                </mdb-btn>
              </div>
            </div>
            <div class="plus d-flex no-print">
              <mdb-btn class="ml-2" size="sm" outline="info" style="font-size:9px; height:30px;" @click="printDiv()">
                Печат
              </mdb-btn>
              <mdb-btn class="ml-2" size="sm" outline="danger" style="font-size:9px; height:30px;" @click="savePdf">
                PDF
              </mdb-btn>
            </div>
          </div>
        </form>

        <div class="report-subtitle">
          <span>{{ Start_time }} ➡️ {{ End_time }}</span>
          <span v-if="worker_name" class="ml-2">| {{ worker_name }}</span>
        </div>

        <div class="summary-cards">
          <div class="summary-card summary-green">
            <div class="summary-title">Общий приход</div>
            <div class="summary-value">{{ formatNumber(totalPrixodSum) }} <small>сум</small></div>
            <div class="summary-sub">
              <span>UZS: {{ formatNumber(totalPrixodUzs) }}</span>
              <span>USD: {{ formatNumber(totalPrixodUsd) }}</span>
            </div>
          </div>
          <div class="summary-card summary-red">
            <div class="summary-title">Общий расход</div>
            <div class="summary-value">{{ formatNumber(totalRasxodSum) }} <small>сум</small></div>
            <div class="summary-sub">
              <span>UZS: {{ formatNumber(totalRasxodUzs) }}</span>
              <span>USD: {{ formatNumber(totalRasxodUsd) }}</span>
            </div>
          </div>
        </div>

        <div class="worker-all-table-wrapper">
          <table class="worker-all-table">
            <thead>
              <tr class="header">
                <th width="40" class="text-left">№</th>
                <th>Источник</th>
                <th>Счет</th>
                <th>Тип</th>
                <th>{{$t('summ')}}</th>
                <th>UZS</th>
                <th>USD</th>
                <th width="90">Курс</th>
                <th>Кассир</th>
                <th>{{$t('date')}}</th>
                <th>{{$t('note')}}</th>
              </tr>
            </thead>
            <tbody>
              <tr v-for="(row, rowIndex) in combinedList" :key="rowIndex"
                :class="{'text_success': row.status_rasxod == 1, 'text_danger': row.status_rasxod == 0}">
                <td><small>{{rowIndex + 1}}</small></td>
                <td><small>{{row.source}}</small></td>
                <td><small>{{row.hisob_name || '-'}}</small></td>
                <td>
                  <small :class="{'text-success': row.status_rasxod == 1, 'text-danger': row.status_rasxod == 0}">
                    {{ row.status_rasxod == 1 ? 'Приход' : 'Расход' }}
                  </small>
                </td>
                <td><small :class="{'text-success': row.status_rasxod == 1, 'text-danger': row.status_rasxod == 0}">{{row.all_summ_string}}</small></td>
                <td><small :class="{'text-success': row.status_rasxod == 1, 'text-danger': row.status_rasxod == 0}">{{getUzs(row)}}</small></td>
                <td><small :class="{'text-success': row.status_rasxod == 1, 'text-danger': row.status_rasxod == 0}">{{row.dollor_string}}</small></td>
                <td><small v-if="row.kurs">{{formatKurs(row.kurs)}}</small></td>
                <td><small>{{row.addiotionala_information}}</small></td>
                <td><small v-if="row.created_date">{{formatDate(row.created_date)}}</small></td>
                <td><small>{{row.note}}</small></td>
              </tr>
              <tr v-if="combinedList.length === 0">
                <td colspan="11" class="text-center p-3">Ma'lumot topilmadi</td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
  import erpSelect from "../../components/erpSelectFioSearch.vue";
  import { mdbBtn, mdbInput, mdbIcon } from 'mdbvue';
  import {mapActions, mapGetters} from 'vuex'
  export default {
    components: {
      mdbBtn,
      mdbInput,
      mdbIcon,
      erpSelect
    },
    data(){
      return{
        Start_time: null,
        End_time: null,
        worker_name: '',
        worker_id: 0,
        workerRasxodList: [],
        mainKassaList: [],
        hisoblarList: [],
        hisob_list_access: [],
        loading: false,
        isPdfGenerating: false,
      }
    },
    async mounted(){
      let time1 = new Date();
      this.Start_time = time1.toISOString().slice(0,10);
      this.End_time = time1.toISOString().slice(0,10);
      await this.fetchWorker();
      await this.fetchHisobAccess();
    },
    computed: {
      ...mapGetters(['allWorker']),
      combinedList(){
        const list = [];
        const shouldInclude = (item) => {
          const raw = (item && item.all_summ_string !== undefined && item.all_summ_string !== null)
            ? item.all_summ_string.toString()
            : '';
          const numeric = parseFloat(raw.replace(/\s/g, '').replace(',', '.')) || 0;
          return numeric !== 0;
        };
        this.workerRasxodList.forEach(item => {
          if (shouldInclude(item)) {
            list.push({...item, source: 'Ежедневные отчет', hisob_name: ''});
          }
        });
        this.mainKassaList.forEach(item => {
          if (shouldInclude(item)) {
            list.push({...item, source: '💵 Асосий касса', hisob_name: ''});
          }
        });
        this.hisoblarList.forEach(item => {
          if (shouldInclude(item)) {
            list.push({...item, source: '💳 Счета', hisob_name: item.hisob_name || ''});
          }
        });
        return list.sort((a, b) => {
          const da = new Date(a.created_date || 0).getTime();
          const db = new Date(b.created_date || 0).getTime();
          return db - da;
        });
      },
      totalPrixodSum() {
        return this.combinedList.reduce((sum, row) => {
          if (row.status_rasxod != 1) return sum;
          return sum + this.parseAmount(row.all_summ_string);
        }, 0);
      },
      totalRasxodSum() {
        return this.combinedList.reduce((sum, row) => {
          if (row.status_rasxod != 0) return sum;
          return sum + this.parseAmount(row.all_summ_string);
        }, 0);
      },
      totalPrixodUzs() {
        return this.combinedList.reduce((sum, row) => {
          if (row.status_rasxod != 1) return sum;
          return sum + this.parseAmount(row.image_url);
        }, 0);
      },
      totalRasxodUzs() {
        return this.combinedList.reduce((sum, row) => {
          if (row.status_rasxod != 0) return sum;
          return sum + this.parseAmount(row.reserve);
        }, 0);
      },
      totalPrixodUsd() {
        return this.combinedList.reduce((sum, row) => {
          if (row.status_rasxod != 1) return sum;
          return sum + this.parseAmount(row.dollor_string);
        }, 0);
      },
      totalRasxodUsd() {
        return this.combinedList.reduce((sum, row) => {
          if (row.status_rasxod != 0) return sum;
          return sum + this.parseAmount(row.dollor_string);
        }, 0);
      }
    },
    methods: {
      ...mapActions(['fetchWorker']),
      async fetchHisobAccess(){
        try{
          const res = await fetch(this.$store.state.hostname + '/TegirmonUserHisobAccess/GetHisoblarByUserId?user_id=' + localStorage.user_id);
          const data = await res.json();
          if(res.status == 200 || res.status == 201){
            this.hisob_list_access = data || [];
          } else {
            this.hisob_list_access = [];
          }
        }
        catch{
          this.hisob_list_access = [];
        }
      },
      async selectOptionWorker(option){
        this.worker_name = option.fio || '';
        this.worker_id = option.id || 0;
        await this.apply();
      },
      formatDate(dateValue) {
        if (!dateValue) return '';
        return dateValue.slice(8,10) + '-' + dateValue.slice(5,7) + '-' + dateValue.slice(0,4) + ' ' + dateValue.slice(11,16);
      },
      formatKurs(value) {
        return value.toString().replace(/(\d)(?=(\d{3})+(\.(\d){0,2})*$)/g, '$1 ');
      },
      parseAmount(value) {
        if (value === null || value === undefined) return 0;
        const raw = value.toString().replace(/\s/g, '').replace(',', '.');
        const num = parseFloat(raw);
        return isNaN(num) ? 0 : num;
      },
      formatNumber(value) {
        if (value === null || value === undefined) return '0';
        const num = Number(value) || 0;
        return num.toLocaleString('ru-RU');
      },
      getUzs(row) {
        if (row.status_rasxod == 1) return row.image_url || '';
        return row.reserve || '';
      },
      async apply(){
        if (!this.worker_id) {
          return;
        }
        const b_date  = this.Start_time + 'T00:00:35.000Z';
        const e_date  = this.End_time + 'T23:59:35.000Z';
        this.workerRasxodList = [];
        this.mainKassaList = [];
        this.hisoblarList = [];
        this.loading = true;
        try{
          const workerRes = await fetch(this.$store.state.hostname + "/TegirmonUserRasxod/getPaginationWorkerListByWorkerId?page=0&size=10000&begin_date=" + b_date + "&end_date=" + e_date + '&worker_id=' + this.worker_id);
          if(workerRes.status == 200 || workerRes.status == 201){
            const data = await workerRes.json();
            this.workerRasxodList = data.items_list || [];
          }
        } catch {}
        try{
          const mainRes = await fetch(this.$store.state.hostname + "/TegirmonMainKassaRasxod/getPaginationByWorker_name?page=0&size=10000&begin_date=" + b_date + "&end_date=" + e_date + '&worker_name_str=' + encodeURIComponent(this.worker_name));
          if(mainRes.status == 200 || mainRes.status == 201){
            const data = await mainRes.json();
            this.mainKassaList = data.items_list || [];
          }
        } catch {}
        try{
          if (this.hisob_list_access.length > 0) {
            const responses = await Promise.all(this.hisob_list_access.map(async (hisob) => {
              const res = await fetch(this.$store.state.hostname + "/TegirmonHisoblarRasxod/getPaginationByWorker_name?page=0&size=10000&begin_date=" + b_date + "&end_date=" + e_date + '&worker_name_str=' + encodeURIComponent(this.worker_name) + "&hisob_id=" + hisob.id);
              if(res.status == 200 || res.status == 201){
                const data = await res.json();
                return (data.items_list || []).map(item => ({...item, hisob_name: hisob.name || ''}));
              }
              return [];
            }));
            this.hisoblarList = responses.flat();
          }
        } catch {}
        this.loading = false;
      },
      ensureHtml2Pdf() {
        return new Promise((resolve, reject) => {
          if (window.html2pdf) {
            resolve(window.html2pdf);
            return;
          }

          const existing = document.getElementById("html2pdf-script");
          if (existing) {
            existing.addEventListener("load", () => resolve(window.html2pdf));
            existing.addEventListener("error", () => reject(new Error("html2pdf load failed")));
            return;
          }

          const script = document.createElement("script");
          script.id = "html2pdf-script";
          script.src = "https://cdn.jsdelivr.net/npm/html2pdf.js@0.10.1/dist/html2pdf.bundle.min.js";
          script.onload = () => resolve(window.html2pdf);
          script.onerror = () => reject(new Error("html2pdf load failed"));
          document.body.appendChild(script);
        });
      },
      printDiv() {
        let divContents = document.getElementById("worker_all_rasxod_print").innerHTML;

        let styles = "";
        document.querySelectorAll('link[rel="stylesheet"], style').forEach((node) => {
          styles += node.outerHTML;
        });

        let printWindow = window.open("", "", "height=800,width=1000");

        let html =
          '<html>' +
          '<head>' +
          '<title>📋 Сводный расход сотрудника</title>' +
          styles +
          '<style>' +
          '@page { size: A4; margin: 5mm; }' +
          '@media print { ' +
          'body { zoom: 0.7; -webkit-print-color-adjust: exact !important; print-color-adjust: exact !important; color-adjust: exact !important; }' +
          '.no-print { display: none !important; }' +
          '.worker-all-table-wrapper { max-height: none !important; overflow: visible !important; }' +
          '}' +
          '</style>' +
          '</head>' +
          '<body>' +
          divContents +
          '<script>window.onafterprint = function() { window.close(); }<\/script>' +
          '</body>' +
          '</html>';
        printWindow.document.open();
        printWindow.document.write(html);
        printWindow.document.close();
        printWindow.focus();
        setTimeout(() => {
          printWindow.print();
        }, 1000);
      },
      async savePdf() {
        const tableSource = document.querySelector("#worker_all_rasxod_print .worker-all-table");
        const subtitleSource = document.querySelector("#worker_all_rasxod_print .report-subtitle");
        const summarySource = document.querySelector("#worker_all_rasxod_print .summary-cards");
        if (!tableSource) return;

        const tempContainer = document.createElement("div");
        tempContainer.style.position = "fixed";
        tempContainer.style.left = "-10000px";
        tempContainer.style.top = "0";
        tempContainer.style.background = "#fff";
        const a4WidthPx = 1080; // A4 landscape at 96dpi
        tempContainer.style.width = `${a4WidthPx}px`;

        const wrapper = document.createElement("div");
        wrapper.style.width = `${a4WidthPx}px`;
        wrapper.style.paddingBottom = "20px";

        if (subtitleSource) {
          const subtitleClone = subtitleSource.cloneNode(true);
          wrapper.appendChild(subtitleClone);
        }
        if (summarySource) {
          const summaryClone = summarySource.cloneNode(true);
          wrapper.appendChild(summaryClone);
        }

        const tableClone = tableSource.cloneNode(true);
        tableClone.style.width = `${a4WidthPx}px`;
        wrapper.appendChild(tableClone);

        const pageStyle = document.createElement("style");
        pageStyle.textContent = `
          .report-subtitle { page-break-after: avoid; }
          .summary-cards { page-break-after: avoid; }
          .worker-all-table { page-break-before: auto; }
          .worker-all-table { page-break-inside: auto; }
          .worker-all-table tr { page-break-inside: avoid; page-break-after: auto; break-inside: avoid; }
          .worker-all-table td, .worker-all-table th { page-break-inside: avoid; break-inside: avoid; }
        `;
        wrapper.appendChild(pageStyle);

        tempContainer.appendChild(wrapper);
        document.body.appendChild(tempContainer);

        try {
          this.isPdfGenerating = true;
          await this.$nextTick();
          await new Promise(resolve => setTimeout(resolve, 800));
          const now = new Date();
          const pad = (value) => String(value).padStart(2, "0");
          const timestamp = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())} ${pad(now.getHours())}-${pad(now.getMinutes())}-${pad(now.getSeconds())}`;
          const workerName = this.worker_name || "Worker";
          const html2pdf = await this.ensureHtml2Pdf();
          await html2pdf()
            .from(wrapper)
            .set({
              margin: 5,
              filename: `📋 ${workerName} (${timestamp}).pdf`,
              pagebreak: { mode: ['css', 'legacy'], avoid: '.worker-all-table tr' },
              html2canvas: { scale: 2.5, useCORS: true, backgroundColor: "#ffffff", logging: false },
              jsPDF: { unit: "mm", format: "a4", orientation: "landscape" }
            })
            .save();
        } finally {
          document.body.removeChild(tempContainer);
          this.isPdfGenerating = false;
        }
      }
    }
  };
</script>

<style lang="scss" scoped>
.report-subtitle{
  margin: 6px 0 12px;
  font-size: 12px;
  color: #3a4b52;
}
.summary-cards{
  display: flex;
  gap: 12px;
  margin-bottom: 12px;
  flex-wrap: wrap;
}
.summary-card{
  flex: 1;
  min-width: 260px;
  background: #f8fafc;
  border: 1px solid #e2e8f0;
  border-radius: 10px;
  padding: 10px 12px;
  box-shadow: 0 2px 6px rgba(15, 23, 42, 0.08);
}
.summary-green{
  border-left: 4px solid #10b981;
}
.summary-red{
  border-left: 4px solid #ef4444;
}
.summary-title{
  font-size: 12px;
  font-weight: 600;
  color: #475569;
}
.summary-value{
  font-size: 18px;
  font-weight: 700;
  color: #111827;
  margin-top: 4px;
}
.summary-sub{
  display: flex;
  gap: 12px;
  font-size: 11px;
  color: #6b7280;
  margin-top: 4px;
}
.pdf-progress{
  position: fixed;
  top: 12px;
  right: 12px;
  z-index: 9999;
  background: rgba(255, 255, 255, 0.98);
  border: 1px solid #e2e8f0;
  border-radius: 10px;
  padding: 8px 12px;
  font-size: 12px;
  font-weight: 600;
  color: #1f2937;
  display: flex;
  align-items: center;
  gap: 8px;
  box-shadow: 0 10px 24px rgba(15, 23, 42, 0.18);
}
.pdf-progress-dot{
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: #2563eb;
  box-shadow: 0 0 0 4px rgba(37, 99, 235, 0.15);
  animation: pdfPulse 1s ease-in-out infinite;
}
@keyframes pdfPulse {
  0% { transform: scale(1); opacity: 0.7; }
  50% { transform: scale(1.25); opacity: 1; }
  100% { transform: scale(1); opacity: 0.7; }
}
.worker-all-table-wrapper{
  overflow-x: auto;
  max-height: calc(100vh - 250px);
  overflow-y: auto;
}
.worker-all-table{
  table-layout: fixed;
  width: 100%;
  font-size: 11px;
  border-collapse: collapse;
}
.worker-all-table tr {
  page-break-inside: avoid !important;
  break-inside: avoid !important;
}
.worker-all-table th,
.worker-all-table td{
  text-align: left;
  padding: 4px 6px;
  border-bottom: 1px solid #e6e9ef;
  page-break-inside: avoid !important;
  break-inside: avoid !important;
}
.worker-all-table td {
  white-space: normal;
  word-break: break-word;
  line-height: 1.3;
  font-size: 14px;
}
.worker-all-table thead {
  display: table-header-group; /* MUHIM */
}
.worker-all-table tfoot {
  display: table-footer-group;
}
.worker-all-table thead th{
  background: #C4DEE4;
  font-weight: 600;
  font-size: 11px;
}
.text_success{
  background: #e6faeb;
}
.text_danger{
  background: #ffebeb;
}
@media print {
  .no-print{
    display: none !important;
  }
  .worker-all-table-wrapper{
    max-height: none !important;
    overflow: visible !important;
  }
}
</style>
